pub struct Payment {
    pub from: String,
    pub to: String,
    pub amount: u64,
    pub nonce: u64,
}

pub fn validate_payment(payment: &Payment) -> Result<(), String> {
    if payment.from.trim().is_empty() {
        return Err("from address is required".to_string());
    }
    if payment.to.trim().is_empty() {
        return Err("to address is required".to_string());
    }
    if payment.amount == 0 {
        return Err("amount must be greater than zero".to_string());
    }
    Ok(())
}

pub struct LedgerHeader {
    pub height: u64,
    pub previous_hash: [u8; 32],
    pub timestamp_ms: u64,
}

pub fn next_ledger_height(parent: &LedgerHeader) -> Option<u64> {
    parent.height.checked_add(1)
}

pub fn storage_fee(byte_count: usize, fee_per_byte: u64) -> Option<u64> {
    let byte_count_u64: u64 = byte_count.try_into().ok()?;
    byte_count_u64.checked_mul(fee_per_byte)
}

use std::collections::HashSet;

pub fn remember_transaction(seen: &mut HashSet<String>, tx_id: String) -> bool {
    seen.insert(tx_id)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub struct CoinAmount(u64);

impl CoinAmount {
    pub fn new(value: u64) -> Self {
        Self(value)
    }

    pub fn as_u64(&self) -> u64 {
        self.0
    }

    pub fn checked_add(self, other: Self) -> Option<Self> {
        self.0.checked_add(other.0).map(Self)
    }

    pub fn checked_sub(self, other: Self) -> Option<Self> {
        self.0.checked_sub(other.0).map(Self)
    }
}

pub fn parse_coin_amount(input: &str) -> Result<u64, String> {
    let trimmed = input.trim();
    if trimmed.is_empty() {
        return Err("amount is required".to_string());
    }
    trimmed
        .parse::<u64>()
        .map_err(|_| "amount must be a non-negative integer".to_string())
}

pub fn debit_balance(balance: u64, amount: u64) -> Result<u64, String> {
    balance
        .checked_sub(amount)
        .ok_or_else(|| "insufficient funds".to_string())
}

use std::collections::HashMap;

pub fn get_balance(balances: &HashMap<String, u64>, account: &str) -> u64 {
    balances.get(account).copied().unwrap_or(0)
}

pub struct SignedTransaction {
    pub id: String,
    pub signer: String,
    pub payload_hash: [u8; 32],
    pub signature: Vec<u8>,
}

pub fn has_signature(tx: &SignedTransaction) -> bool {
    !tx.signer.trim().is_empty() && !tx.signature.is_empty()
}

pub fn validate_nonce(expected: u64, actual: u64) -> Result<(), String> {
    if actual == expected {
        Ok(())
    } else {
        Err(format!("invalid nonce: expected {expected}, got {actual}"))
    }
}
